function solve(s) {
  const attributes = s.match(/[^=]*/g).map(attr => attr.trim());
  const result = {};

  for (const attr of attributes) {
    if (attr.startsWith('href')) {
      result.href = attr.trim().toLowerCase();
    } else if (attr.startsWith('target')) {
      if (attr.trim().toLowerCase() !== '_blank' && attr.trim().toLowerCase() !== '_self' && attr.trim().toLowerCase() !== '_parent' && attr.trim().toLowerCase() !== '_top') {
        result.target = '_blank';
      }
    } else if (attr.startsWith('title')) {
      result.title = attr.trim().toLowerCase();
    }
  }

  return result;
}

// Do not modify the following code
