class Solution:
    def solve(self, s: str) -> dict:
        attributes = s.split()
        result = {}

        for attr in attributes:
            if attr.startswith('href'):
                result['href'] = attr.strip().lower()
            elif attr.startswith('target'):
                if attr.strip().lower() not in ['_blank', '_self', '_parent', '_top']:
                    result['target'] = '_blank'
            elif attr.startswith('title'):
                result['title'] = attr.strip().lower()
        return result

# Do not modify the following code
def parse_html(s):
    return s

return Solution().solve(parse_html(s))
